class LedgerEvent {
  final String id;
  final DateTime occurredAt;
  final int sequence;

  const LedgerEvent({
    required this.id,
    required this.occurredAt,
    required this.sequence,
  });
}

class EventCursor {
  DateTime? _lastTime;

  bool accept(LedgerEvent event) {
    final lastTime = _lastTime;
    if (lastTime != null && !event.occurredAt.isAfter(lastTime)) {
      return false;
    }
    _lastTime = event.occurredAt;
    return true;
  }
}

