import 'event_cursor.dart';

class EventInbox {
  final EventCursor _cursor;

  EventInbox([EventCursor? cursor]) : _cursor = cursor ?? EventCursor();

  List<LedgerEvent> applyBatch(Iterable<LedgerEvent> events) {
    final ordered = events.toList()
      ..sort((left, right) {
        final byTime = left.occurredAt.compareTo(right.occurredAt);
        if (byTime != 0) {
          return byTime;
        }
        return right.sequence.compareTo(left.sequence);
      });

    final accepted = <LedgerEvent>[];
    for (final event in ordered) {
      if (_cursor.accept(event)) {
        accepted.add(event);
      }
    }
    return accepted;
  }
}

