import '../lib/event_cursor.dart';
import '../lib/inbox.dart';

void main() {
  final earlier = DateTime.utc(2026, 7, 1, 10, 0, 0);
  final later = earlier.add(const Duration(seconds: 1));
  final accepted = EventInbox().applyBatch([
    LedgerEvent(id: 'later', occurredAt: later, sequence: 1),
    LedgerEvent(id: 'earlier', occurredAt: earlier, sequence: 9),
  ]);

  final ids = accepted.map((event) => event.id).join(',');
  if (ids != 'earlier,later') {
    throw StateError('expected chronological events, got $ids');
  }
}
